import { generateText } from 'ai';
import { vex } from '@vex_dev/sdk';

const vexMiddleware = vex.middleware({
  rules: [
    vex.block.bias({ protectedClasses: ['race', 'gender', 'age', 'disability'] }),
    vex.require.structured({ schema: z.object({ score: z.number(), rationale: z.string() }) })
  ]
});

export async function evaluateCandidate(resume: string, jobDescription: string) {
  const result = await generateText({
    model: 'gpt-4o',
    prompt: `Evaluate this resume for ${jobDescription}`,
    ...vexMiddleware
  });
  return result.text;
}

import { streamText } from 'ai';
import { vex } from '@vex_dev/sdk';

const hrGuardrails = vex.stream({
  blocks: [
    vex.block.hallucination(),
    vex.block("discriminatory language"),
    vex.enforce.schema({
      type: 'candidate_ranking',
      properties: { rank: { type: 'number' }, protectedScore: { type: 'number', max: 0.1 } }
    })
  ],
  audit: true
});

export async function streamCandidateRanking(resumes: string[]) {
  const stream = await streamText({
    model: 'claude-3-5-sonnet-20240620',
    prompt: 'Rank these candidates by fit...',
    ...hrGuardrails
  });
  return stream;
}

